import { Routes } from '@angular/router';

import { AdministrationPageComponent } from './pages/administration-page.component';
import { HomePageComponent } from './pages/home-page.component';
import { IngestExecutionsPageComponent } from './pages/ingest-executions-page.component';
import { IngestRunPageComponent } from './pages/ingest-run-page.component';
import { IngestWorkflowsPageComponent } from './pages/ingest-workflows-page.component';
import { ModelBuildPageComponent } from './pages/model-build-page.component';

export const routes: Routes = [
  {
	path: '',
	pathMatch: 'full',
	redirectTo: 'home',
  },
  {
	path: 'home',
	component: HomePageComponent,
  },
  {
	path: 'ingest/workflows',
	component: IngestWorkflowsPageComponent,
  },
  {
	path: 'ingest/run',
	component: IngestRunPageComponent,
  },
  {
	path: 'ingest/executions',
	component: IngestExecutionsPageComponent,
  },
  {
	path: 'model-build',
	component: ModelBuildPageComponent,
  },
  {
	path: 'administration',
	component: AdministrationPageComponent,
  },
  {
	path: '**',
	redirectTo: 'home',
  },
];

import { Routes } from '@angular/router';

export const routes: Routes = [
  {
	path: '',
	pathMatch: 'full',
	redirectTo: 'home',
  },
  {
	path: 'home',
	loadComponent: () => import('./pages/home-page.component').then((m) => m.HomePageComponent),
  },
  {
	path: 'ingest/workflows',
	loadComponent: () => import('./pages/ingest-workflows-page.component').then((m) => m.IngestWorkflowsPageComponent),
  },
  {
	path: 'ingest/run',
	loadComponent: () => import('./pages/ingest-run-page.component').then((m) => m.IngestRunPageComponent),
  },
  {
	path: 'ingest/executions',
	loadComponent: () => import('./pages/ingest-executions-page.component').then((m) => m.IngestExecutionsPageComponent),
  },
  {
	path: 'model-build',
	loadComponent: () => import('./pages/model-build-page.component').then((m) => m.ModelBuildPageComponent),
  },
  {
	path: 'administration',
	loadComponent: () => import('./pages/administration-page.component').then((m) => m.AdministrationPageComponent),
  },
  {
	path: '**',
	redirectTo: 'home',
  },
];

import { NgClass } from '@angular/common';
import { Component } from '@angular/core';
import { NavigationEnd, Router, RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { filter } from 'rxjs';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, NgClass],
  templateUrl: './app.html',
  styleUrl: './app.css'
})
export class App {
  currentUrl = '/home';

  constructor(private readonly router: Router) {
    this.currentUrl = this.router.url;
    this.router.events
      .pipe(filter((event): event is NavigationEnd => event instanceof NavigationEnd))
      .subscribe((event: NavigationEnd) => {
        this.currentUrl = event.urlAfterRedirects;
      });
  }

  isIngestDomain(): boolean {
    return this.currentUrl.startsWith('/ingest');
  }
}

import { NgClass } from '@angular/common';
import { Component, signal } from '@angular/core';
import { NavigationEnd, Router, RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { filter } from 'rxjs';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [RouterOutlet, RouterLink, RouterLinkActive, NgClass],
  templateUrl: './app.html',
  styleUrl: './app.css'
})
export class App {
  currentUrl = '/home';
  readonly theme = signal<'light' | 'dark'>(this.getStoredTheme());

  constructor(private readonly router: Router) {
    this.applyTheme(this.theme());
    this.currentUrl = this.router.url;
    this.router.events
      .pipe(filter((event): event is NavigationEnd => event instanceof NavigationEnd))
      .subscribe((event: NavigationEnd) => {
        this.currentUrl = event.urlAfterRedirects;
      });
  }

  isIngestDomain(): boolean {
    return this.currentUrl.startsWith('/ingest');
  }

  toggleTheme(): void {
    const next = this.theme() === 'dark' ? 'light' : 'dark';
    this.theme.set(next);
    this.applyTheme(next);
    localStorage.setItem('infohub.theme', next);
  }

  isDarkTheme(): boolean {
    return this.theme() === 'dark';
  }

  private applyTheme(theme: 'light' | 'dark'): void {
    document.documentElement.setAttribute('data-theme', theme);
  }

  private getStoredTheme(): 'light' | 'dark' {
    const stored = localStorage.getItem('infohub.theme');
    if (stored === 'dark' || stored === 'light') {
      return stored;
    }
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
}

export interface WorkflowLastExecutionSummary {
  execution_id?: string | null;
  status: string;
  started_at?: string | null;
  completed_at?: string | null;
}

export interface WorkflowSummary {
  module: string;
  workflow_selector: string;
  workflow_parent: string;
  workflow_child: string;
  workflow_id: string;
  display_name: string;
  short_description: string;
  last_execution: WorkflowLastExecutionSummary;
}

export interface WorkflowFieldOption {
  label: string;
  value: string;
}

export interface WorkflowFieldSchema {
  key: string;
  label: string;
  type: string;
  description?: string;
  placeholder?: string;
  required?: boolean;
  default?: unknown;
  read_only?: boolean;
  min?: number;
  max?: number;
  pattern?: string;
  options?: WorkflowFieldOption[];
}

export interface WorkflowDetail extends WorkflowSummary {
  title: string;
  description: string;
  fields: WorkflowFieldSchema[];
  raw_config: Record<string, unknown>;
}

export interface ExecutionSummary {
  execution_id: string;
  workflow_selector: string;
  workflow_id: string;
  workflow_parent: string;
  workflow_child: string;
  module_name: string;
  display_name: string;
  status: string;
  return_code?: number | null;
  active_run_folder?: string | null;
  reused_latest_run?: boolean;
  started_at: string;
  completed_at?: string | null;
}

export interface ExecutionDetail extends ExecutionSummary {
  request_payload: Record<string, unknown>;
  effective_config: Record<string, unknown>;
  response_summary: Record<string, unknown>;
  error_message?: string | null;
}

export interface ExecutionPage {
  items: ExecutionSummary[];
  page: number;
  page_size: number;
  total_items: number;
  total_pages: number;
}

import { AsyncPipe, DatePipe, NgClass } from '@angular/common';
import { Component, inject, signal } from '@angular/core';
import { FormBuilder, ReactiveFormsModule } from '@angular/forms';
import { Observable, catchError, map, of, switchMap, tap } from 'rxjs';

import { ExecutionPage } from '../models';

import { WorkflowApiService } from '../services/workflow-api.service';

@Component({
  selector: 'app-ingest-executions-page',
  standalone: true,
  imports: [ReactiveFormsModule, AsyncPipe, DatePipe, NgClass],
  template: `
    <section class="content-card">
      <div class="d-flex flex-wrap justify-content-between align-items-start gap-3 mb-3">
        <div>
          <h2 class="page-heading">Ingest Executions</h2>
          <p class="page-subtitle">Track run history, filter by workflow and status, and review recent operational activity.</p>
        </div>
        <div class="btn-group" role="group" aria-label="Table density">
          <button
            type="button"
            class="btn"
            [ngClass]="density() === 'comfortable' ? 'btn-primary' : 'btn-outline-primary'"
            (click)="setDensity('comfortable')"
          >
            <i class="fa-solid fa-table-cells-large me-1"></i>Comfortable
          </button>
          <button
            type="button"
            class="btn"
            [ngClass]="density() === 'compact' ? 'btn-primary' : 'btn-outline-primary'"
            (click)="setDensity('compact')"
          >
            <i class="fa-solid fa-table-cells me-1"></i>Compact
          </button>
        </div>
      </div>

      <form [formGroup]="filtersForm" (ngSubmit)="refresh(1)" class="sticky-toolbar p-3 mb-3">
        <div class="row g-3 align-items-end">
          <div class="col-md-6 col-xl-3">
            <label class="form-label fw-semibold">Workflow</label>
            <select class="form-select" formControlName="workflow_id">
              <option value="">All</option>
              @for (item of workflowOptions(); track item.workflow_id) {
                <option [value]="item.workflow_id">{{ item.display_name }} ({{ item.workflow_id }})</option>
              }
            </select>
          </div>
          <div class="col-md-6 col-xl-2">
            <label class="form-label fw-semibold">Status</label>
            <select class="form-select" formControlName="status">
              <option value="">All</option>
              <option>IN_PROGRESS</option>
              <option>COMPLETED</option>
              <option>FAILED</option>
              <option>SKIPPED</option>
              <option>Never Executed</option>
            </select>
          </div>
          <div class="col-md-6 col-xl-3">
            <label class="form-label fw-semibold">Started From</label>
            <input class="form-control" type="datetime-local" formControlName="started_from" />
          </div>
          <div class="col-md-6 col-xl-3">
            <label class="form-label fw-semibold">Started To</label>
            <input class="form-control" type="datetime-local" formControlName="started_to" />
          </div>
          <div class="col-xl-1 d-grid gap-2">
            <button class="btn btn-primary" type="submit"><i class="fa-solid fa-filter me-1"></i>Apply</button>
            <button class="btn btn-outline-secondary" type="button" (click)="clear()">Clear</button>
          </div>
        </div>
      </form>

      @if (error()) {
        <div class="alert alert-danger py-2">{{ error() }}</div>
      }

      @if (pageData$ | async; as pageData) {
        <p class="table-note mb-2">
          Showing page {{ pageData.page }} of {{ pageData.total_pages || 1 }} ({{ pageData.total_items }} total executions)
        </p>
        <div class="execution-table-wrap">
          <table class="table table-hover execution-table" [ngClass]="density() === 'compact' ? 'compact-density' : 'comfortable-density'">
            <thead>
              <tr>
                <th>Execution ID</th>
                <th>Workflow</th>
                <th>Status</th>
                <th>Started</th>
                <th>Completed</th>
                <th>Run Folder</th>
              </tr>
            </thead>
            <tbody>
              @for (row of pageData.items; track row.execution_id) {
                <tr>
                  <td><code>{{ row.execution_id }}</code></td>
                  <td>
                    <div class="fw-semibold">{{ row.display_name }}</div>
                    <small class="text-secondary">{{ row.workflow_id }}</small>
                  </td>
                  <td>
                    <span [ngClass]="statusClass(row.status)">
                      <i class="fa-solid" [ngClass]="statusIcon(row.status)"></i>
                      {{ row.status }}
                    </span>
                  </td>
                  <td>{{ row.started_at | date: 'medium' }}</td>
                  <td>{{ row.completed_at ? (row.completed_at | date: 'medium') : '-' }}</td>
                  <td>{{ row.active_run_folder || '-' }}</td>
                </tr>
              }
              @if (!pageData.items.length) {
                <tr>
                  <td colspan="6" class="text-center py-4">
                    <div class="empty-state p-3">
                      <i class="fa-regular fa-folder-open me-2"></i>No executions found for this filter set.
                    </div>
                  </td>
                </tr>
              }
            </tbody>
          </table>
        </div>

        <div class="d-flex flex-wrap justify-content-between align-items-center gap-2 mt-3">
          <button class="btn btn-outline-secondary" type="button" [disabled]="pageData.page <= 1" (click)="refresh(pageData.page - 1)">
            <i class="fa-solid fa-arrow-left me-1"></i>Previous
          </button>
          <span class="small text-secondary">Page {{ pageData.page }} / {{ pageData.total_pages || 1 }}</span>
          <button class="btn btn-outline-secondary" type="button" [disabled]="pageData.page >= pageData.total_pages" (click)="refresh(pageData.page + 1)">
            Next<i class="fa-solid fa-arrow-right ms-1"></i>
          </button>
        </div>
      }
    </section>
  `,
})
export class IngestExecutionsPageComponent {
  private readonly api = inject(WorkflowApiService);
  private readonly fb = inject(FormBuilder);

  readonly error = signal<string | null>(null);
  readonly workflowOptions = signal<Array<{ workflow_id: string; display_name: string }>>([]);
  readonly page = signal(1);
  readonly density = signal<'compact' | 'comfortable'>(this.readDensity());

  readonly filtersForm = this.fb.group({
    workflow_id: [''],
    status: [''],
    started_from: [''],
    started_to: [''],
  });

  pageData$: Observable<ExecutionPage> = this.api.getWorkflows('ingest').pipe(
    tap((workflows) => {
      this.workflowOptions.set(workflows.map((workflow) => ({ workflow_id: workflow.workflow_id, display_name: workflow.display_name })));
    }),
    switchMap(() => this.fetchPage(this.page())),
    catchError((err) => {
      this.error.set(err?.error?.detail ?? 'Unable to load executions.');
      return of({ items: [], page: 1, page_size: 15, total_items: 0, total_pages: 1 });
    }),
  );

  refresh(page: number): void {
    this.page.set(page);
    this.pageData$ = this.fetchPage(page);
  }

  clear(): void {
    this.filtersForm.reset({ workflow_id: '', status: '', started_from: '', started_to: '' });
    this.refresh(1);
  }

  setDensity(value: 'compact' | 'comfortable'): void {
    this.density.set(value);
    localStorage.setItem('infohub.executions.density', value);
  }

  statusClass(status: string): string {
    const normalized = (status || '').toUpperCase();
    if (normalized.includes('COMPLETE')) {
      return 'status-badge status-success';
    }
    if (normalized.includes('IN_PROGRESS')) {
      return 'status-badge status-warning';
    }
    if (normalized.includes('FAILED')) {
      return 'status-badge status-danger';
    }
    return 'status-badge status-neutral';
  }

  statusIcon(status: string): string {
    const normalized = (status || '').toUpperCase();
    if (normalized.includes('COMPLETE')) {
      return 'fa-circle-check';
    }
    if (normalized.includes('IN_PROGRESS')) {
      return 'fa-hourglass-half';
    }
    if (normalized.includes('FAILED')) {
      return 'fa-triangle-exclamation';
    }
    return 'fa-circle-minus';
  }

  private readDensity(): 'compact' | 'comfortable' {
    const stored = localStorage.getItem('infohub.executions.density');
    return stored === 'compact' ? 'compact' : 'comfortable';
  }

  private fetchPage(page: number) {
    const values = this.filtersForm.value;
    return this.api
      .getExecutions({
        module_name: 'ingest',
        workflow_id: values.workflow_id || undefined,
        status: values.status || undefined,
        started_from: values.started_from || undefined,
        started_to: values.started_to || undefined,
        page,
        page_size: 15,
      })
      .pipe(
        map((data) => {
          this.error.set(null);
          return data;
        }),
        catchError((err) => {
          this.error.set(err?.error?.detail ?? 'Unable to load executions.');
          return of({ items: [], page, page_size: 15, total_items: 0, total_pages: 1 });
        }),
      );
  }
}

import { AsyncPipe, JsonPipe } from '@angular/common';
import { Component, inject, signal } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { catchError, of, switchMap, tap } from 'rxjs';

import { WorkflowDetail, WorkflowFieldSchema } from '../models';
import { WorkflowApiService } from '../services/workflow-api.service';

@Component({
  selector: 'app-ingest-run-page',
  standalone: true,
  imports: [AsyncPipe, ReactiveFormsModule, JsonPipe],
  template: `
    <section class="content-card">
      <h2>Run Ingest Workflow</h2>
      <p>This page renders input fields and validations dynamically from workflow metadata.</p>

      <p>Workflow run form is generated dynamically from workflow field metadata in config.</p>
        @if (workflow) {
          <h3>{{ workflow.title }}</h3>
          <p>{{ workflow.description }}</p>
          <p><strong>Selector:</strong> <code>{{ workflow.workflow_selector }}</code></p>
          <p><strong>Workflow ID:</strong> <code>{{ workflow.workflow_id }}</code></p>

          @if (form()) {
            <form [formGroup]="form()!" (ngSubmit)="submit(workflow)">
              <div class="dynamic-grid">
        <h3>{{ workflow.title }}</h3>
        <p>{{ workflow.description }}</p>
        <p><strong>Selector:</strong> {{ workflow.workflow_selector }}</p>
        <p><strong>Workflow ID:</strong> {{ workflow.workflow_id }}</p>
                      @case ('textarea-list') {
                        <textarea
        @if (form()) {
          <form [formGroup]="form()!" (ngSubmit)="submit(workflow)">
            <div class="dynamic-grid">
              @for (field of workflow.fields; track field.key) {
                <div class="field-block">
                  <label [for]="field.key">{{ field.label }}</label>
                  @switch (field.type) {
                    @case ('textarea-list') {
                      <textarea
                        [id]="field.key"
                        [formControlName]="field.key"
                        rows="4"
                        [placeholder]="field.description || 'One value per line'"
                      ></textarea>
                    }
                    @case ('multiselect') {
                      <select [id]="field.key" [formControlName]="field.key" multiple>
                        @for (option of optionsFor(field); track option.value) {
                        @for (option of field.options || []; track option.value) {
                        }
                      </select>
                    }
                    @case ('checkbox') {
                      <input [id]="field.key" type="checkbox" [formControlName]="field.key" />
                    }
                    @default {
                      <input
                        [id]="field.key"
                        [type]="inputType(field)"
                        [formControlName]="field.key"
                        [placeholder]="field.placeholder || ''"
                      />
                    }
                  }
                  @if (field.description) {
                    <small>{{ field.description }}</small>
                  }
                </div>
              }
            </div>
            <button class="btn-primary" type="submit" [disabled]="isSubmitting()">{{ isSubmitting() ? 'Running...' : 'Run' }}</button>
          </form>
  readonly apiConnected = signal(true);
  readonly form = signal<FormGroup | null>(null);
  readonly isSubmitting = signal(false);
  readonly runResponse = signal<Record<string, unknown> | null>(null);

  readonly workflow$ = this.route.queryParamMap.pipe(
    switchMap((params: import('@angular/router').ParamMap) => {
      const selector = params.get('workflow') || 'ingest/AWSBedrock';
      return this.api.getWorkflowDetail(selector).pipe(
        tap((workflow: WorkflowDetail) => {
          this.apiConnected.set(true);
          this.error.set(null);
        }),
      );
    }),
    catchError((err: unknown) => {
      const detail = typeof err === 'object' && err !== null && 'error' in err ? (err as { error?: { detail?: string } }).error?.detail : null;
      const fallback = FALLBACK_WORKFLOW_DETAILS['ingest/AWSBedrock'];
      this.apiConnected.set(false);
    switchMap((params) => {
      this.form.set(this.buildForm(fallback.fields));
      return of(fallback);
    }),
  );

        tap((workflow: WorkflowDetail) => this.form.set(this.buildForm(workflow.fields))),
      return 'url';
    }
    return 'text';
  }

  private buildForm(fields: WorkflowFieldSchema[]): FormGroup {
        tap((workflow) => this.form.set(this.buildForm(workflow.fields))),
    catchError((err) => {
      this.error.set(err?.error?.detail ?? 'Unable to load workflow details.');
      if (field.type === 'textarea-list' && Array.isArray(defaultValue)) {
        defaultValue = defaultValue.join('\n');
      }
      controls[field.key] = this.fb.control(defaultValue ?? '', validators);
    });
    return this.fb.group(controls);
  }

  submit(workflow: WorkflowDetail): void {
    if (!this.apiConnected()) {
      this.error.set('API is unavailable. Start backend before submitting a workflow run.');
      return;
    }

    const form = this.form();
    if (!form || form.invalid) {
      const value = form.get(field.key)?.value;
      if (field.type === 'textarea-list') {
        inputPayload[field.key] = String(value || '')
          .split('\n')
          .map((item) => item.trim())
          .filter((item) => item.length > 0);
      } else if (field.type === 'multiselect') {
        inputPayload[field.key] = Array.isArray(value) ? value : [];
      } else {
        inputPayload[field.key] = value;
      }
    }

    this.isSubmitting.set(true);
    this.error.set(null);
    this.runResponse.set(null);
    this.api.runIngestWorkflow(workflow.workflow_selector, inputPayload).subscribe({
      next: (response: unknown) => {
        this.runResponse.set(response as unknown as Record<string, unknown>);
        this.isSubmitting.set(false);
      },
      error: (err) => {
        this.error.set(err?.error?.detail ?? 'Failed to submit workflow run.');
      error: (err: unknown) => {
        const detail = typeof err === 'object' && err !== null && 'error' in err ? (err as { error?: { detail?: string } }).error?.detail : null;
      next: (response) => {
        this.error.set(detail ?? 'Failed to submit workflow run.');
        this.isSubmitting.set(false);
      },
    });
  }
}

import { AsyncPipe, JsonPipe } from '@angular/common';
import { Component, inject, signal } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { catchError, of, switchMap, tap } from 'rxjs';

import { FALLBACK_WORKFLOW_DETAILS } from '../fallback-workflow-data';
import { WorkflowDetail, WorkflowFieldOption, WorkflowFieldSchema } from '../models';
import { WorkflowApiService } from '../services/workflow-api.service';

@Component({
  selector: 'app-ingest-run-page',
  standalone: true,
  imports: [AsyncPipe, ReactiveFormsModule, JsonPipe],
  template: `
    <section class="content-card">
      <div class="d-flex flex-wrap justify-content-between align-items-start gap-3 mb-3">
        <div>
          <h2 class="page-heading">Run Ingest Workflow</h2>
          <p class="page-subtitle">Dynamic input form generated directly from workflow metadata and validation rules.</p>
        </div>
      </div>

      @if (!apiConnected()) {
        <div class="alert info-alert mb-3">
          <div class="fw-semibold mb-1"><i class="fa-solid fa-triangle-exclamation me-2"></i>API unavailable.</div>
          <div>Form metadata is loaded from local fallback data.</div>
          <div class="small mt-1">Start backend to run live executions:</div>
          <pre class="mb-0 mt-2"><code>npm run start:api
npm run start:api-ui</code></pre>
        </div>
      }

      @if (error()) {
        <div class="alert alert-danger py-2">{{ error() }}</div>
      }

      @if (workflow$ | async; as workflow) {
        @if (workflow) {
          <div class="card border-0 bg-light-subtle mb-3">
            <div class="card-body">
              <div class="d-flex flex-wrap justify-content-between align-items-start gap-2">
                <div>
                  <h3 class="h4 mb-1"><i class="fa-solid fa-diagram-project me-2 text-primary"></i>{{ workflow.title }}</h3>
                  <p class="text-secondary mb-2">{{ workflow.description }}</p>
                </div>
              </div>
              <div class="small text-secondary">
                Selector: <code>{{ workflow.workflow_selector }}</code>
                <span class="mx-2">|</span>
                Workflow ID: <code>{{ workflow.workflow_id }}</code>
              </div>
            </div>
          </div>

          @if (form()) {
            <form [formGroup]="form()!" (ngSubmit)="submit(workflow)">
              <div class="row g-3 mb-3">
                @for (field of workflow.fields; track field.key) {
                  <div class="col-md-6 col-xl-4">
                    <div class="h-100 p-3 border rounded-3 bg-white">
                      <label class="form-label fw-semibold" [for]="field.key">{{ field.label }}</label>
                    @switch (field.type) {
                      @case ('textarea-list') {
                        <textarea
                          class="form-control"
                          [id]="field.key"
                          [formControlName]="field.key"
                          rows="4"
                          [placeholder]="field.description || 'One value per line'"
                        ></textarea>
                      }
                      @case ('multiselect') {
                        <select class="form-select" [id]="field.key" [formControlName]="field.key" multiple>
                          @for (option of optionsFor(field); track option.value) {
                            <option [value]="option.value">{{ option.label }}</option>
                          }
                        </select>
                      }
                      @case ('checkbox') {
                        <div class="form-check mt-1">
                          <input class="form-check-input" [id]="field.key" type="checkbox" [formControlName]="field.key" />
                        </div>
                      }
                      @default {
                        <input
                          class="form-control"
                          [id]="field.key"
                          [type]="inputType(field)"
                          [formControlName]="field.key"
                          [placeholder]="field.placeholder || ''"
                        />
                      }
                    }
                    @if (field.description) {
                      <small class="text-secondary d-block mt-2">{{ field.description }}</small>
                    }
                    </div>
                  </div>
                }
              </div>
              <div class="d-flex justify-content-end">
                <button class="btn btn-primary px-4" type="submit" [disabled]="isSubmitting() || !apiConnected()">
                  <i class="fa-solid" [class.fa-spinner]="isSubmitting()" [class.fa-spin]="isSubmitting()" [class.fa-play]="!isSubmitting()"></i>
                  <span class="ms-2">{{ isSubmitting() ? 'Running...' : 'Run Workflow' }}</span>
                </button>
              </div>
            </form>
          }
        }
      }

      @if (runResponse()) {
        <section class="mt-4">
          <h3 class="h5 mb-2"><i class="fa-solid fa-circle-check text-success me-2"></i>Execution Submitted</h3>
          <pre class="border rounded-3 bg-light p-3 mb-0">{{ runResponse() | json }}</pre>
        </section>
      }
    </section>
  `,
})
export class IngestRunPageComponent {
  private readonly api = inject(WorkflowApiService);
  private readonly route = inject(ActivatedRoute);
  private readonly fb = inject(FormBuilder);

  readonly error = signal<string | null>(null);
  readonly apiConnected = signal(true);
  readonly form = signal<FormGroup | null>(null);
  readonly isSubmitting = signal(false);
  readonly runResponse = signal<Record<string, unknown> | null>(null);

  readonly workflow$ = this.route.queryParamMap.pipe(
    switchMap((params: import('@angular/router').ParamMap) => {
      const selector = params.get('workflow') || 'ingest/AWSBedrock';
      return this.api.getWorkflowDetail(selector).pipe(
        tap((workflow: WorkflowDetail) => {
          this.apiConnected.set(true);
          this.error.set(null);
          this.form.set(this.buildForm(workflow.fields));
        }),
      );
    }),
    catchError((err: unknown) => {
      const detail = typeof err === 'object' && err !== null && 'error' in err ? (err as { error?: { detail?: string } }).error?.detail : null;
      const fallback = FALLBACK_WORKFLOW_DETAILS['ingest/AWSBedrock'];
      this.apiConnected.set(false);
      this.error.set(detail ?? 'Unable to load workflow details from API.');
      this.form.set(this.buildForm(fallback.fields));
      return of(fallback);
    }),
  );

  optionsFor(field: WorkflowFieldSchema): WorkflowFieldOption[] {
    return field.options ?? [];
  }

  inputType(field: WorkflowFieldSchema): string {
    if (field.type === 'number') {
      return 'number';
    }
    if (field.type === 'url') {
      return 'url';
    }
    return 'text';
  }

  private buildForm(fields: WorkflowFieldSchema[]): FormGroup {
    const controls: Record<string, FormControl> = {};
    fields.forEach((field) => {
      const validators = [];
      if (field.required) {
        validators.push(Validators.required);
      }
      if (field.type === 'number') {
        if (field.min !== undefined) {
          validators.push(Validators.min(field.min));
        }
        if (field.max !== undefined) {
          validators.push(Validators.max(field.max));
        }
      }
      let defaultValue: unknown = field.default;
      if (field.type === 'textarea-list' && Array.isArray(defaultValue)) {
        defaultValue = defaultValue.join('\n');
      }
      controls[field.key] = this.fb.control(defaultValue ?? '', validators);
    });
    return this.fb.group(controls);
  }

  submit(workflow: WorkflowDetail): void {
    if (!this.apiConnected()) {
      this.error.set('API is unavailable. Start backend before submitting a workflow run.');
      return;
    }

    const form = this.form();
    if (!form || form.invalid) {
      form?.markAllAsTouched();
      return;
    }

    const inputPayload: Record<string, unknown> = {};
    for (const field of workflow.fields) {
      const value = form.get(field.key)?.value;
      if (field.type === 'textarea-list') {
        inputPayload[field.key] = String(value || '')
          .split('\n')
          .map((item) => item.trim())
          .filter((item) => item.length > 0);
      } else if (field.type === 'multiselect') {
        inputPayload[field.key] = Array.isArray(value) ? value : [];
      } else {
        inputPayload[field.key] = value;
      }
    }

    this.isSubmitting.set(true);
    this.error.set(null);
    this.runResponse.set(null);
    this.api.runIngestWorkflow(workflow.workflow_selector, inputPayload).subscribe({
      next: (response: unknown) => {
        this.runResponse.set(response as unknown as Record<string, unknown>);
        this.isSubmitting.set(false);
      },
      error: (err: unknown) => {
        const detail = typeof err === 'object' && err !== null && 'error' in err ? (err as { error?: { detail?: string } }).error?.detail : null;
        this.error.set(detail ?? 'Failed to submit workflow run.');
        this.isSubmitting.set(false);
      },
    });
  }
}

:root {
  --ih-bg: #f3f6fb;
  --ih-surface: #ffffff;
  --ih-soft: #eef4ff;
  --ih-border: #d9e2ef;
  --ih-text: #1f2a3d;
  --ih-muted: #5a6c84;
  --ih-brand: #2f6fec;
  --ih-brand-strong: #1f58cf;
  --ih-success-bg: #dcfce7;
  --ih-success-text: #166534;
  --ih-warn-bg: #fff3cd;
  --ih-warn-text: #8a5500;
  --ih-danger-bg: #fee2e2;
  --ih-danger-text: #991b1b;
  --ih-neutral-bg: #e9edf4;
  --ih-neutral-text: #344054;
  --ih-shadow: 0 8px 30px rgba(18, 36, 67, 0.08);
}

html,
body {
  min-height: 100%;
}

body {
  margin: 0;
  background: linear-gradient(180deg, #edf4ff 0%, #f8fbff 220px, var(--ih-bg) 100%);
  color: var(--ih-text);
  font-family: Inter, 'Segoe UI', Roboto, Arial, sans-serif;
}

.content-card {
  width: min(1280px, 100%);
  background: var(--ih-surface);
  border: 1px solid var(--ih-border);
  border-radius: 16px;
  box-shadow: var(--ih-shadow);
  padding: 1.25rem;
}

.page-heading {
  font-size: clamp(1.2rem, 1rem + 0.6vw, 1.7rem);
  font-weight: 700;
  margin: 0;
}

.page-subtitle {
  color: var(--ih-muted);
  margin: 0.25rem 0 0;
}

.metric-card {
  border: 1px solid var(--ih-border);
  background: var(--ih-soft);
  border-radius: 12px;
  padding: 0.75rem 0.85rem;
}

.metric-label {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--ih-muted);
}

.metric-value {
  font-weight: 700;
  margin-top: 0.15rem;
}

.status-badge {
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 700;
  padding: 0.35rem 0.6rem;
  display: inline-flex;
  gap: 0.35rem;
  align-items: center;
}

.status-success {
  background: var(--ih-success-bg);
  color: var(--ih-success-text);
}

.status-warning {
  background: var(--ih-warn-bg);
  color: var(--ih-warn-text);
}

.status-danger {
  background: var(--ih-danger-bg);
  color: var(--ih-danger-text);
}

.status-neutral {
  background: var(--ih-neutral-bg);
  color: var(--ih-neutral-text);
}

.workflow-card {
  border: 1px solid var(--ih-border);
  border-radius: 14px;
  background: linear-gradient(180deg, #ffffff 0%, #f7faff 100%);
  box-shadow: 0 8px 26px rgba(19, 42, 74, 0.06);
}

.workflow-card .card-title {
  margin-bottom: 0.25rem;
}

.workflow-card .meta-line {
  color: var(--ih-muted);
  font-size: 0.9rem;
  margin-bottom: 0.3rem;
}

.icon-pill {
