.workflow-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--ih-shadow-soft);
}

.workflow-card .card-title {
  margin-bottom: 0.25rem;
}

.workflow-card .meta-line {
  color: var(--ih-muted);
  font-size: 0.9rem;
  margin-bottom: 0.3rem;
}

.icon-pill {
  width: 40px;
  height: 40px;
  border-radius: 10px;
  background: color-mix(in srgb, var(--ih-brand) 14%, transparent);
  color: var(--ih-brand-strong);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 1.05rem;
}

.sticky-toolbar {
  position: sticky;
  top: 72px;
  z-index: 12;
  background: color-mix(in srgb, var(--ih-surface) 90%, transparent);
  border: 1px solid var(--ih-border);
  border-radius: 12px;
  backdrop-filter: blur(5px);
}

.execution-table-wrap {
  border: 1px solid var(--ih-border);
  border-radius: 12px;
  overflow: auto;
}

.execution-table {
  margin-bottom: 0;
}

.execution-table thead th {
  position: sticky;
  top: 0;
  z-index: 2;
  background: var(--ih-table-head);
  font-size: 0.82rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: #3d506b;
}

.execution-table.compact-density td,
.execution-table.compact-density th {
  padding-top: 0.4rem;
  padding-bottom: 0.4rem;
}

.execution-table.comfortable-density td,
.execution-table.comfortable-density th {
  padding-top: 0.85rem;
  padding-bottom: 0.85rem;
}

.table-note {
  color: var(--ih-muted);
  font-size: 0.85rem;
}

.info-alert {
  border: 1px solid #f2d38b;
  background: #fffbef;
  border-radius: 10px;
}

.empty-state {
  border: 1px dashed var(--ih-border);
  border-radius: 12px;
  background: color-mix(in srgb, var(--ih-soft) 65%, var(--ih-surface));
  color: var(--ih-muted);
}

code {
  background: var(--ih-code-bg);
  border: 1px solid var(--ih-code-border);
  color: var(--ih-code-text);
  border-radius: 6px;
  padding: 0.05rem 0.35rem;
}

.btn,
.nav-link,
.form-control,
.form-select,
.card,
.status-badge {
  transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
}

.btn:active {
  transform: translateY(1px);
}

.btn:focus-visible,
.nav-link:focus-visible,
.form-control:focus-visible,
.form-select:focus-visible {
  box-shadow: 0 0 0 0.2rem var(--ih-focus);
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

@media (max-width: 991.98px) {
  .sticky-toolbar {
	top: 64px;
  }

  .content-card {
	padding: 1rem;
  }
}

from fastapi import APIRouter, HTTPException, Query

from app.Api.services.workflow_config_service import get_workflow_detail, list_workflows

router = APIRouter(prefix="/workflows", tags=["workflows"])


@router.get("")
def get_workflows(domain: str | None = Query(default=None)):
    return list_workflows(domain=domain)


@router.get("/{workflow_selector:path}")
def get_workflow(workflow_selector: str):
    try:
        return get_workflow_detail(workflow_selector)
    except ValueError as exc:
        raise HTTPException(status_code=404, detail=str(exc)) from exc

class ExecCtxData:
    def __init__(self):
        self.ctx_data: dict = {}

    def add_ctx_data(self, key: str, value) -> None:
        self.ctx_data.update({key: value})

    def get_ctx_data(self) -> dict:
        return self.ctx_data

    def get_ctx_data_by_key(self, key: str):
        return self.ctx_data.get(key)

